class Solution:
	def solve(self, graph):
		n = len(graph)
		visited = [False] * n
		count = 0
		for i in range(n):
			if not visited[i]:
				count += 1
				self._dfs(graph, i, visited)
			return count

	def _dfs(self, graph, u, visited):
		stack = [u]
		while stack:
			v = stack.pop()
			visited[v] = True
			for neighbor in graph[v]:
				if not visited[neighbor]:
					stack.append(neighbor)
