#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
int solve(vector<vector<int>>& graph)
{
	int n = graph.size();
	vector<bool> visited(n);
	int count = 0;
	function<void(int)> dfs = [&](int u) {
		visited[u] = true;
		for (auto v : graph[u]) {
			if (!visited[v]) {
				count++;
				dfs(v);
			}
		}
	}
;
	for (int i = 0; i < n; ++i) {
		if (!visited[i]) {
			count++;
			dfs(i);
		}
	}
		return count;
}
};
int main() {
	ios_base::sync_with_stdio(false);
	cin.tie(nullptr);
	Solution s;
	int n; cin >> n;
	vector<vector<int>> graph(n);
	for (int i = 0; i < n; ++i) {
		int m; cin >> m;
		graph[i].resize(m);
		for (int j = 0; j < m; ++j) cin >> graph[i][j];
	}
	cout << s.solve(graph) << endl;
	return 0;
}
